import React from 'react'
import requests from '../requests'
import { Link } from 'react-router-dom'
import { useMediaQuery } from 'react-responsive'


function MovieCard({movie,isLarge,mediaType}) {
    
    // extract movie infos
    const backdrop_path = requests.image_api+movie.backdrop_path
    const poster_path = requests.image_api+movie.poster_path
    const poster_path_for_phone = requests.small_image_api+movie.poster_path
    const {id,title,vote_average} = movie
    const isPhone = useMediaQuery({query:'(max-width:460px)'})
    return (
        <div className={isLarge?"MovieCardLarge":"MovieCard"}>
            <Link to={{
                pathname:`/all-about/${movie.media_type ? movie.media_type:mediaType}/${movie.id}`
                // ,
                // state:{
                //     movie:movie
                // }
            }}>
                <img src={isLarge?backdrop_path:isPhone?poster_path_for_phone:poster_path} alt={title} key={id} data-mediatype={movie.media_type}/>
            </Link>
            <h4 className="voteAvarage">{vote_average} ⭐</h4>
        </div>
    )
}

export default MovieCard
